import React from "react";

export default function TechCard({ name, description, logo, reference }) {

  return (

    <div className="tech-card">

      <div style={{display:"flex",alignItems:"center",gap:"10px"}}>

        {logo && (
          <img
            src={logo}
            alt={name}
            style={{width:"36px",height:"36px"}}
          />
        )}

        <span style={{
          fontSize:"28px",
          fontWeight:"bold",
          color:"#666"
        }}>
          {name}
        </span>

      </div>

      <p style={{
        fontSize:"14px",
        marginTop:"6px",
        color:"#444"
      }}>
        {description}
      </p>

      <div style={{marginTop:"10px"}}>

        <button>Guide</button>
        <button>Examples</button>

        <details style={{display:"inline-block",marginLeft:"8px"}}>
          <summary>⋮</summary>

          {reference && (
            <a
              href={reference}
              target="_blank"
              rel="noopener noreferrer"
            >
              Official reference
            </a>
          )}

        </details>

      </div>

    </div>

  );

}
